// Java 25 exam prep - Object serialization
// Learn: write an object to bytes with ObjectOutputStream.
record Account(String id, long cents) implements Serializable {
}

byte[] save(Account account) throws IOException {
    var bytes = new ByteArrayOutputStream();
    try (var out = new ObjectOutputStream(bytes)) {
        // ObjectOutputStream writes Serializable objects.
        out.writeObject(account);
    }
    return bytes.toByteArray();
}
